import{_ as t,a,b as o,c as l,d as n}from"./chunks/编辑配置.T0puvWjh.js";import{_ as r,o as d,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Telegram चैनल जोड़ना","description":"","frontmatter":{},"headers":[],"relativePath":"hi/upload/telegram.md","filePath":"hi/upload/telegram.md","lastUpdated":1781962217000}'),c={name:"hi/upload/telegram.md"};function h(p,e,m,b,g,u){return d(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="telegram-चैनल-जोड़ना" tabindex="-1">Telegram चैनल जोड़ना <a class="header-anchor" href="#telegram-चैनल-जोड़ना" aria-label="Permalink to &quot;Telegram चैनल जोड़ना&quot;">​</a></h1><h2 id="शुरू-करने-से-पहले-क्या-चाहिए" tabindex="-1">शुरू करने से पहले क्या चाहिए <a class="header-anchor" href="#शुरू-करने-से-पहले-क्या-चाहिए" aria-label="Permalink to &quot;शुरू करने से पहले क्या चाहिए&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ज़रूरत</th><th>उपयोग</th></tr></thead><tbody><tr><td>Telegram अकाउंट</td><td>bot और storage channel बनाने के लिए।</td></tr><tr><td><code>@BotFather</code></td><td>Telegram bot बनाने के लिए।</td></tr><tr><td>Telegram channel</td><td>फ़ाइलों की अंतिम storage destination।</td></tr><tr><td><code>@userinfobot</code></td><td>channel <code>Chat ID</code> पता करने के लिए।</td></tr></tbody></table><h2 id="कहाँ-जोड़ें" tabindex="-1">कहाँ जोड़ें <a class="header-anchor" href="#कहाँ-जोड़ें" aria-label="Permalink to &quot;कहाँ जोड़ें&quot;">​</a></h2><ol><li>System Settings खोलें।</li><li>Upload Settings पर जाएँ।</li><li>ऊपर दाएँ कोने में Add Channel पर क्लिक करें।</li><li><code>Telegram</code> चुनें।</li></ol><h2 id="फ़ील्ड-संदर्भ" tabindex="-1">फ़ील्ड संदर्भ <a class="header-anchor" href="#फ़ील्ड-संदर्भ" aria-label="Permalink to &quot;फ़ील्ड संदर्भ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>फ़ील्ड</th><th>क्या करता है</th><th>आवश्यक</th></tr></thead><tbody><tr><td>Channel name</td><td>इस चैनल का आसान नाम, जैसे &quot;Telegram Primary&quot;।</td><td>हाँ</td></tr><tr><td>Active</td><td>इस चैनल को चालू या बंद करता है।</td><td>सुझाया गया</td></tr><tr><td>Bot Token</td><td>आपके Telegram bot का token।</td><td>हाँ</td></tr><tr><td>Session ID (Chat ID)</td><td>Telegram channel का ID।</td><td>हाँ</td></tr><tr><td>Relay Proxy URL (optional)</td><td>केवल तब उपयोग करें जब Telegram access अस्थिर हो। <code>https://</code> सहित पूरा proxy URL डालें।</td><td>नहीं</td></tr><tr><td>Remark</td><td>आगे की maintenance के लिए notes।</td><td>नहीं</td></tr></tbody></table><h2 id="सेटअप-स्टेप्स" tabindex="-1">सेटअप स्टेप्स <a class="header-anchor" href="#सेटअप-स्टेप्स" aria-label="Permalink to &quot;सेटअप स्टेप्स&quot;">​</a></h2><h3 id="_1-telegram-bot-बनाएँ" tabindex="-1">1. Telegram bot बनाएँ <a class="header-anchor" href="#_1-telegram-bot-बनाएँ" aria-label="Permalink to &quot;1. Telegram bot बनाएँ&quot;">​</a></h3><ol><li>Telegram खोलें और <code>@BotFather</code> खोजें।</li><li>chat खोलकर <code>Start</code> पर क्लिक करें।</li><li><code>/newbot</code> भेजें।</li><li>prompts के अनुसार bot display name दर्ज करें।</li><li>prompts के अनुसार bot username दर्ज करें। आम तौर पर username का अंत <code>bot</code> से होना चाहिए।</li><li>bot बन जाने के बाद <code>@BotFather</code> एक bot token लौटाएगा।</li></ol><p>यही token ImgBed में <code>Bot Token</code> फ़ील्ड में डालना है।</p><p><img src="'+t+'" alt="Bot token सेव करें" loading="lazy"></p><h3 id="_2-channel-बनाएँ" tabindex="-1">2. Channel बनाएँ <a class="header-anchor" href="#_2-channel-बनाएँ" aria-label="Permalink to &quot;2. Channel बनाएँ&quot;">​</a></h3><ol><li>Telegram में New Channel पर क्लिक करें।</li><li>channel name दर्ज करें।</li><li>channel बनाना पूरा करें।</li></ol><p>Public और private, दोनों तरह के channels इस्तेमाल किए जा सकते हैं।</p><p><img src="'+a+'" alt="Channel बनाएँ" loading="lazy"></p><h3 id="_3-bot-को-channel-में-जोड़ें" tabindex="-1">3. Bot को channel में जोड़ें <a class="header-anchor" href="#_3-bot-को-channel-में-जोड़ें" aria-label="Permalink to &quot;3. Bot को channel में जोड़ें&quot;">​</a></h3><ol><li>अभी बनाया गया channel खोलें।</li><li>channel settings खोलें।</li><li>member या administrator जोड़ें।</li><li>अपने बनाए हुए bot username को खोजें।</li><li>bot को channel में जोड़ें।</li></ol><p>सबसे भरोसेमंद uploads के लिए bot को administrator permissions देना बेहतर है।</p><p><img src="'+o+'" alt="Bot को channel में invite करें" loading="lazy"></p><h3 id="_4-user-info-get-id-idbot-से-channel-id-लें" tabindex="-1">4. User Info - Get ID - IDbot से Channel ID लें <a class="header-anchor" href="#_4-user-info-get-id-idbot-से-channel-id-लें" aria-label="Permalink to &quot;4. User Info - Get ID - IDbot से Channel ID लें&quot;">​</a></h3><ol><li>Telegram में <code>@userinfobot</code> खोजें। इसका display name आम तौर पर <code>User Info - Get ID - IDbot</code> होता है।</li><li>chat खोलकर <code>Start</code> पर क्लिक करें।</li><li>bot के विकल्पों में से <code>Channel</code> चुनें।</li><li>message picker में target channel चुनकर <code>@userinfobot</code> को भेजें।</li><li>जब <code>@userinfobot</code> result लौटाए, तो <code>Id: -100...</code> में दिखा number copy करें।</li></ol><p><code>-100</code> से शुरू होने वाला number ImgBed के लिए ज़रूरी <code>Session ID (Chat ID)</code> है।</p><p><img src="'+l+'" alt="Channel ID लें" loading="lazy"></p><h3 id="_5-imgbed-में-telegram-channel-भरें" tabindex="-1">5. ImgBed में Telegram channel भरें <a class="header-anchor" href="#_5-imgbed-में-telegram-channel-भरें" aria-label="Permalink to &quot;5. ImgBed में Telegram channel भरें&quot;">​</a></h3><p>channel configuration dialog पर लौटें और fields ऐसे भरें:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>custom channel name, जैसे <code>TelegramPrimary</code>।</td></tr><tr><td>Active</td><td>चालू रखना सुझाया गया है।</td></tr><tr><td>Bot Token</td><td><code>@BotFather</code> से मिला bot token।</td></tr><tr><td>Session ID (Chat ID)</td><td><code>@userinfobot</code> से मिला <code>-100...</code> number।</td></tr><tr><td>Relay Proxy URL (optional)</td><td>केवल ज़रूरत होने पर, जैसे <code>https://your-tg-proxy.example.com</code>।</td></tr><tr><td>Remark</td><td>वैकल्पिक notes।</td></tr></tbody></table><p>सब भरने के बाद Save पर क्लिक करें।</p><p><img src="'+n+`" alt="Configuration edit करें" loading="lazy"></p><h2 id="कैसे-जाँचें" tabindex="-1">कैसे जाँचें <a class="header-anchor" href="#कैसे-जाँचें" aria-label="Permalink to &quot;कैसे जाँचें&quot;">​</a></h2><table tabindex="0"><thead><tr><th>जाँच</th><th>कैसे verify करें</th></tr></thead><tbody><tr><td>Channel card दिखता है</td><td>save करने के बाद Upload Settings page में Telegram channel card दिखना चाहिए।</td></tr><tr><td>Channel enable रह सकता है</td><td>Active switch चालू रहना चाहिए।</td></tr><tr><td>Configuration save हुई</td><td>detail view में Bot Token और Chat ID saved दिखने चाहिए।</td></tr><tr><td>Upload काम करता है</td><td>test image upload करें और target Telegram channel में उसके आने की पुष्टि करें।</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@BotFather से bot बनाएँ</span></span>
<span class="line"><span>-&gt; Bot Token save करें</span></span>
<span class="line"><span>-&gt; Telegram channel बनाएँ</span></span>
<span class="line"><span>-&gt; bot को channel में जोड़ें और administrator permissions दें</span></span>
<span class="line"><span>-&gt; @userinfobot खोजें और Channel चुनें</span></span>
<span class="line"><span>-&gt; channel से कोई message @userinfobot को forward करें</span></span>
<span class="line"><span>-&gt; लौटाया गया Id: -100... copy करें</span></span>
<span class="line"><span>-&gt; ImgBed में Bot Token और Chat ID डालें</span></span>
<span class="line"><span>-&gt; save करें और test image upload करें</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const T=r(c,[["render",h]]);export{k as __pageData,T as default};
